sql:
SELECT target_id, campaign_id, customer_segment
FROM campaign_targets
WHERE campaign_id = 2 AND demographics = 'urban';

SELECT segment_id, COUNT(customer_id) AS number_of_customers
FROM customer_segment_memberships
GROUP BY segment_id;

SELECT cb.behavior_type, COUNT(cb.behavior_id) AS total_frequency
FROM customer_behavior cb
GROUP BY cb.behavior_type;

SELECT customers.first_name || ' ' || customers.last_name AS full_name, customer_types.customer_type_name
FROM customers
JOIN customer_types ON customers.customer_type_id = customer_types.customer_type_id;

SELECT campaign_name 
FROM marketing_campaigns 
WHERE campaign_id NOT IN (SELECT campaign_id FROM campaign_targets);
